
-- Drop existing tables to recreate with correct data types
drop table if exists public.sav_tickets cascade;
drop table if exists public.debts cascade;
drop table if exists public.cheques cascade;
drop table if exists public.transactions cascade;
drop table if exists public.stock cascade;
drop table if exists public.partners cascade;

-- 1. PARTNERS (using text IDs from CSV)
create table public.partners (
    id text primary key,
    name text not null,
    type text not null,
    email text,
    phone text,
    address text,
    city text,
    ice text,
    if_id text,
    created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 2. STOCK
create table public.stock (
    id text primary key,
    name text not null,
    sku text not null,
    category text not null,
    quantity integer default 0 not null,
    min_quantity integer default 5 not null,
    unit_price decimal(12, 2) default 0.00 not null,
    declassed_quantity integer default 0 not null,
    created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 3. TRANSACTIONS
create table public.transactions (
    id text primary key,
    type text not null,
    amount decimal(12, 2) not null,
    description text,
    partner_id text references public.partners(id) on delete set null,
    partner_name text,
    date date not null,
    payment_method text,
    status text not null,
    items jsonb,
    created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 4. CHEQUES
create table public.cheques (
    id text primary key,
    type text not null,
    reference text,
    status text not null,
    partner_name text,
    due_date date,
    amount decimal(12, 2) not null,
    bank text,
    number text,
    received_date date,
    created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 5. SAV TICKETS
create table public.sav_tickets (
    id text primary key,
    client_name text not null,
    client_id text,
    product_name text,
    product_id text,
    ticket_number text,
    description text,
    solution text,
    cost decimal(12, 2) default 0.00,
    status text not null,
    created_at date,
    updated_at date
);
